// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Search the head database
	// (GET /hdb/search)
	SearchHeadDatabase(ctx context.Context, request SearchHeadDatabaseRequestObject) (SearchHeadDatabaseResponseObject, error)
	// Search the head database
	// (GET /hdb/{category})
	GetHeadDatabaseCategory(ctx context.Context, request GetHeadDatabaseCategoryRequestObject) (GetHeadDatabaseCategoryResponseObject, error)
	// Get map player data for a player
	// (GET /map-players/{playerId})
	GetMapPlayerData(ctx context.Context, request GetMapPlayerDataRequestObject) (GetMapPlayerDataResponseObject, error)
	// Get map paginated history for a given player
	// (GET /map-players/{playerId}/history)
	GetMapHistory(ctx context.Context, request GetMapHistoryRequestObject) (GetMapHistoryResponseObject, error)
	// Delete all save states for a player
	// (DELETE /map-players/{playerId}/states)
	DeleteMapPlayerStates(ctx context.Context, request DeleteMapPlayerStatesRequestObject) (DeleteMapPlayerStatesResponseObject, error)
	// Get a player's top times sorted by leaderboard placement
	// (GET /map-players/{playerId}/topTimes)
	GetPlayerTopTimes(ctx context.Context, request GetPlayerTopTimesRequestObject) (GetPlayerTopTimesResponseObject, error)
	// Get requested maps
	// (GET /maps)
	GetMaps(ctx context.Context, request GetMapsRequestObject) (GetMapsResponseObject, error)
	// Create a new map
	// (POST /maps)
	CreateMap(ctx context.Context, request CreateMapRequestObject) (CreateMapResponseObject, error)
	// Get a global leaderboard by its name, optionally including player info
	// (GET /maps/hub/leaderboard/{leaderboardName})
	GetGlobalLeaderboard(ctx context.Context, request GetGlobalLeaderboardRequestObject) (GetGlobalLeaderboardResponseObject, error)
	// Get the progress of multiple maps for a player
	// (GET /maps/progress)
	GetMapProgressBulk(ctx context.Context, request GetMapProgressBulkRequestObject) (GetMapProgressBulkResponseObject, error)
	// Search for maps by configurable query parameters
	// (GET /maps/search)
	SearchMaps(ctx context.Context, request SearchMapsRequestObject) (SearchMapsResponseObject, error)
	// Soft deletes a map
	// (DELETE /maps/{mapId})
	DeleteMap(ctx context.Context, request DeleteMapRequestObject) (DeleteMapResponseObject, error)
	// Get map info by full ID (not published ID)
	// (GET /maps/{mapId})
	GetMap(ctx context.Context, request GetMapRequestObject) (GetMapResponseObject, error)
	// Update map info
	// (PATCH /maps/{mapId})
	UpdateMap(ctx context.Context, request UpdateMapRequestObject) (UpdateMapResponseObject, error)
	// Delete a map leaderboard entirely or for a particular player
	// (DELETE /maps/{mapId}/leaderboard/{leaderboardName})
	DeleteMapLeaderboard(ctx context.Context, request DeleteMapLeaderboardRequestObject) (DeleteMapLeaderboardResponseObject, error)
	// Get a map leaderboard by its name, optionally including player info
	// (GET /maps/{mapId}/leaderboard/{leaderboardName})
	GetMapLeaderboard(ctx context.Context, request GetMapLeaderboardRequestObject) (GetMapLeaderboardResponseObject, error)
	// Restore a map leaderboard from existing save state data, optionally for a single player
	// (POST /maps/{mapId}/leaderboard/{leaderboardName}/restore)
	RestoreMapLeaderboard(ctx context.Context, request RestoreMapLeaderboardRequestObject) (RestoreMapLeaderboardResponseObject, error)
	// Publish a map if it meets all required criterion
	// (POST /maps/{mapId}/publish)
	PublishMap(ctx context.Context, request PublishMapRequestObject) (PublishMapResponseObject, error)
	// Get a player's rating for a map (always returns a response, even with no rating)
	// (GET /maps/{mapId}/ratings/{playerId})
	GetMapRating(ctx context.Context, request GetMapRatingRequestObject) (GetMapRatingResponseObject, error)
	// Update (via upsert) a player's rating for a map
	// (PUT /maps/{mapId}/ratings/{playerId})
	RateMap(ctx context.Context, request RateMapRequestObject) (RateMapResponseObject, error)
	// Submit a report for a map by its full ID
	// (POST /maps/{mapId}/report)
	ReportMap(ctx context.Context, request ReportMapRequestObject) (ReportMapResponseObject, error)
	// Create a new savestate for the given player on the given map
	// (POST /maps/{mapId}/savestates/{playerId})
	CreateSaveState(ctx context.Context, request CreateSaveStateRequestObject) (CreateSaveStateResponseObject, error)
	// Get the best savestate for the given player on the given map
	// (GET /maps/{mapId}/savestates/{playerId}/best)
	GetBestSaveState(ctx context.Context, request GetBestSaveStateRequestObject) (GetBestSaveStateResponseObject, error)
	// Get the latest savestate for the given player on the given map
	// (GET /maps/{mapId}/savestates/{playerId}/latest)
	GetLatestSaveState(ctx context.Context, request GetLatestSaveStateRequestObject) (GetLatestSaveStateResponseObject, error)
	// Delete a savestate
	// (DELETE /maps/{mapId}/savestates/{playerId}/{saveStateId})
	DeleteSaveState(ctx context.Context, request DeleteSaveStateRequestObject) (DeleteSaveStateResponseObject, error)
	// Update a savestate
	// (PATCH /maps/{mapId}/savestates/{playerId}/{saveStateId})
	UpdateSaveState(ctx context.Context, request UpdateSaveStateRequestObject) (UpdateSaveStateResponseObject, error)
	// Removes any pending or completed verification from a map
	// (DELETE /maps/{mapId}/verify)
	DeleteMapVerification(ctx context.Context, request DeleteMapVerificationRequestObject) (DeleteMapVerificationResponseObject, error)
	// Moves a map from the unverified state to the pending state.
	// (POST /maps/{mapId}/verify)
	BeginMapVerification(ctx context.Context, request BeginMapVerificationRequestObject) (BeginMapVerificationResponseObject, error)
	// Get map world data
	// (GET /maps/{mapId}/world)
	GetMapWorld(ctx context.Context, request GetMapWorldRequestObject) (GetMapWorldResponseObject, error)
	// Update map world data
	// (PUT /maps/{mapId}/world)
	UpdateMapWorld(ctx context.Context, request UpdateMapWorldRequestObject) (UpdateMapWorldResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

